use std::env;
use std::error::Error;
use std::fs::File;
use std::process;

use csv::ReaderBuilder;

pub fn count_rows(path: &str, has_header: bool) -> Result<usize, Box<dyn Error>> {
    let file = File::open(path)?;
    let mut reader = ReaderBuilder::new()
        .has_headers(has_header)
        .from_reader(file);

    let mut count = 0usize;
    for result in reader.records() {
        result?;
        count += 1;
    }

    Ok(count)
}

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <path-to-csv>", args[0]);
        process::exit(1);
    }

    match count_rows(&args[1], true) {
        Ok(count) => println!("{}", count),
        Err(err) => {
            eprintln!("Error: {}", err);
            process::exit(1);
        }
    }
}

