        .map_err(|e| format!("could not open '{}': {}", path.display(), e))?;
    let reader = BufReader::new(file);

    let mut rdr = ReaderBuilder::new()
        .has_headers(false)
        .from_reader(reader);

    let mut count = 0usize;
