use std::env;
use std::fs::File;
use std::io::{self, BufRead, BufReader};
use std::process;

struct Config {
    path: String,
    has_header: bool,
}

fn parse_args(args: &[String]) -> Result<Config, String> {
    let mut path: Option<String> = None;
    let mut has_header = false;

    for arg in &args[1..] {
        match arg.as_str() {
            "--has-header" => has_header = true,
            other => {
                if path.is_some() {
                    return Err(format!("unexpected argument: {}", other));
                }
                path = Some(other.to_string());
            }
        }
    }

    let path = path.ok_or_else(|| "missing required argument: <path>".to_string())?;
    Ok(Config { path, has_header })
}

// Counts CSV records, respecting quoted fields that may contain embedded
// newlines (RFC 4180), without loading the whole file into memory.
fn count_rows<R: BufRead>(reader: R, has_header: bool) -> io::Result<u64> {
    let mut count: u64 = 0;
    let mut in_quotes = false;
    let mut row_has_content = false;

    for line in reader.lines() {
        let line = line?;
        row_has_content = true;

        let mut chars = line.chars().peekable();
        while let Some(c) = chars.next() {
            if c == '"' {
                if in_quotes && chars.peek() == Some(&'"') {
                    chars.next();
                } else {
                    in_quotes = !in_quotes;
                }
            }
        }

        if !in_quotes {
            count += 1;
            row_has_content = false;
        }
    }

    if row_has_content {
        count += 1;
    }

    if has_header && count > 0 {
        count -= 1;
    }

    Ok(count)
}

fn run() -> Result<u64, String> {
    let args: Vec<String> = env::args().collect();
    let config = parse_args(&args)?;

    let file = File::open(&config.path)
        .map_err(|e| format!("could not open '{}': {}", config.path, e))?;
    let reader = BufReader::new(file);

    count_rows(reader, config.has_header).map_err(|e| format!("error reading '{}': {}", config.path, e))
}

fn main() {
    match run() {
        Ok(count) => println!("{}", count),
        Err(msg) => {
            eprintln!("error: {}", msg);
            process::exit(1);
        }
    }
}
