use std::env;
use std::process;

use csv::ReaderBuilder;

fn count_rows(path: &str, has_header: bool) -> Result<usize, Box<dyn std::error::Error>> {
    let mut reader = ReaderBuilder::new()
        .has_headers(has_header)
        .from_path(path)?;

    let count = reader.records().try_fold(0usize, |acc, record| {
        record.map(|_| acc + 1)
    })?;

    Ok(count)
}

fn main() {
    let args: Vec<String> = env::args().collect();

    let path = match args.get(1) {
        Some(p) => p,
        None => {
            eprintln!("Usage: {} <path-to-csv> [--no-header]", args[0]);
            process::exit(1);
        }
    };

    let has_header = !args.iter().skip(2).any(|a| a == "--no-header");

    match count_rows(path, has_header) {
        Ok(count) => println!("{}", count),
        Err(e) => {
            eprintln!("Error reading '{}': {}", path, e);
            process::exit(1);
        }
    }
}
