use std::env;
use std::fs::File;
use std::io::{BufReader, Read};
use std::process;

fn print_usage(prog: &str) {
    eprintln!("Usage: {} [--has-header] <path>", prog);
}

/// Counts CSV records from raw file contents, honoring RFC4180-style quoting
/// so that commas/newlines embedded in quoted fields don't split a record.
fn count_csv_rows(contents: &str) -> usize {
    let mut rows = 0usize;
    let mut in_quotes = false;
    let mut saw_any_char_on_row = false;
    let mut chars = contents.chars().peekable();

    while let Some(c) = chars.next() {
        saw_any_char_on_row = true;
        match c {
            '"' => {
                if in_quotes && chars.peek() == Some(&'"') {
                    // escaped quote ("")
                    chars.next();
                } else {
                    in_quotes = !in_quotes;
                }
            }
            '\n' if !in_quotes => {
                rows += 1;
                saw_any_char_on_row = false;
            }
            '\r' if !in_quotes => {
                // handle CRLF: skip, the following \n (if any) will terminate the row
                if chars.peek() == Some(&'\n') {
                    // let the \n branch handle row termination
                } else {
                    rows += 1;
                    saw_any_char_on_row = false;
                }
            }
            _ => {}
        }
    }

    // count a trailing row that has content but no terminating newline
    if saw_any_char_on_row {
        rows += 1;
    }

    rows
}

fn main() {
    let args: Vec<String> = env::args().collect();
    let prog = args.first().cloned().unwrap_or_else(|| "csv_row_counter".to_string());

    let mut has_header = false;
    let mut path: Option<String> = None;

    for arg in &args[1..] {
        match arg.as_str() {
            "--has-header" => has_header = true,
            other => {
                if path.is_some() {
                    print_usage(&prog);
                    process::exit(2);
