use std::env;
use std::fs::File;
use std::io::{self, BufReader, Read};
use std::process;

fn print_usage(program: &str) {
    eprintln!("Usage: {} <path-to-csv> [--has-header]", program);
}

/// Counts CSV records from a reader, correctly handling quoted fields
/// that may contain embedded newlines and escaped quotes ("").
fn count_csv_rows<R: Read>(reader: R) -> io::Result<usize> {
    let mut buf_reader = BufReader::new(reader);
    let mut contents = String::new();
    buf_reader.read_to_string(&mut contents)?;

    if contents.is_empty() {
        return Ok(0);
    }

    let mut row_count = 0usize;
    let mut in_quotes = false;
    let mut seen_any_char_in_row = false;
    let mut chars = contents.chars().peekable();

    while let Some(c) = chars.next() {
        match c {
            '"' => {
                seen_any_char_in_row = true;
                if in_quotes {
                    if chars.peek() == Some(&'"') {
                        // Escaped quote, consume the second quote.
                        chars.next();
                    } else {
                        in_quotes = false;
                    }
                } else {
                    in_quotes = true;
                }
            }
            '\n' if !in_quotes => {
                row_count += 1;
                seen_any_char_in_row = false;
            }
            '\r' if !in_quotes => {
                // Handle bare \r and \r\n line endings; \n case above
                // handles the increment, so just skip \r itself unless
                // it's not followed by \n (old Mac-style line ending).
                if chars.peek() != Some(&'\n') {
                    row_count += 1;
                    seen_any_char_in_row = false;
                }
            }
            _ => {
                seen_any_char_in_row = true;
            }
        }
    }

    // Count a final row if the file doesn't end with a newline.
    if seen_any_char_in_row {
        row_count += 1;
    }

    Ok(row_count)
}

fn run(path: &str, has_header: bool) -> io::Result<usize> {
    let file = File::open(path)?;
    let mut count = count_csv_rows(file)?;

    if has_header && count > 0 {
        count -= 1;
    }

    Ok(count)
}

fn main() {
    let args: Vec<String> = env::args().collect();
    let program = args.get(0).map(String::as_str).unwrap_or("csv_row_counter");

    let mut path: Option<String> = None;
    let mut has_header = false;

    for arg in &args[1..] {
        match arg.as_str() {
            "--has-header" => has_header = true,
            "-h" | "--help" => {
                print_usage(program);
                process::exit(0);
            }
            other => {
                if path.is_some() {
                    eprintln!("Error: unexpected extra argument '{}'", other);
                    print_usage(program);
                    process::exit(2);
                }
                path = Some(other.to_string());
            }
        }
    }

    let path = match path {
        Some(p) => p,
        None => {
            eprintln!("Error: missing required <path-to-csv> argument");
            print_usage(program);
            process::exit(2);
        }
    };

    match run(&path, has_header) {
        Ok(count) => println!("{}", count),
        Err(e) => {
            eprintln!("Error reading '{}': {}", path, e);
            process::exit(1);
        }
    }
}

