use std::env;
use std::fs::File;
use std::io::{self, BufReader};
use std::process;

use csv::ReaderBuilder;

struct Args {
    path: String,
    has_header: bool,
    delimiter: u8,
}

fn parse_args() -> Result<Args, String> {
    let mut path: Option<String> = None;
    let mut has_header = false;
    let mut delimiter: u8 = b',';

    let mut iter = env::args().skip(1);
    while let Some(arg) = iter.next() {
        match arg.as_str() {
            "--has-header" => has_header = true,
            "--delimiter" => {
                let val = iter
                    .next()
                    .ok_or_else(|| "--delimiter requires a value".to_string())?;
                let bytes = val.as_bytes();
                if bytes.len() != 1 {
                    return Err("--delimiter must be a single character".to_string());
                }
                delimiter = bytes[0];
            }
            other => {
                if path.is_some() {
                    return Err(format!("unexpected argument: {other}"));
                }
                path = Some(other.to_string());
            }
        }
    }

    let path = path.ok_or_else(|| "missing required CSV file path argument".to_string())?;

    Ok(Args {
        path,
        has_header,
        delimiter,
    })
}

fn count_rows(args: &Args) -> io::Result<u64> {
    let file = File::open(&args.path)?;
    let reader = BufReader::new(file);

    let mut csv_reader = ReaderBuilder::new()
        .has_headers(args.has_header)
        .delimiter(args.delimiter)
        .from_reader(reader);

    let mut count: u64 = 0;
    for result in csv_reader.records() {
        result?;
        count += 1;
    }

    Ok(count)
}

fn main() {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("Error: {e}");
            eprintln!("Usage: csv_row_counter <path> [--has-header] [--delimiter <char>]");
            process::exit(1);
        }
    };

    match count_rows(&args) {
        Ok(count) => println!("{count} rows"),
        Err(e) => {
            eprintln!("Error reading '{}': {}", args.path, e);
            process::exit(1);
        }
    }
}
