use std::env;
use std::fs::File;
use std::io::{BufReader, Read};
use std::process::exit;

fn strip_bom(s: &str) -> &str {
    s.strip_prefix('\u{feff}').unwrap_or(s)
}

fn count_rows(path: &str, has_header: bool) -> Result<usize, String> {
    if !path.ends_with(".csv") {
        return Err(format!("'{}' does not have a .csv extension", path));
    }

    let file = File::open(path).map_err(|e| format!("could not open '{}': {}", path, e))?;
    let mut reader = BufReader::new(file);
    let mut contents = String::new();
    reader
        .read_to_string(&mut contents)
        .map_err(|e| format!("could not read '{}': {}", path, e))?;

    let contents = strip_bom(&contents);

    let mut count = contents
        .lines()
        .filter(|line| !line.trim().is_empty())
        .count();

    if has_header && count > 0 {
        count -= 1;
    }

    Ok(count)
}

fn main() {
    let args: Vec<String> = env::args().collect();

    if args.len() < 2 {
        eprintln!("Usage: {} <path.csv> [--no-header]", args[0]);
        exit(1);
    }

    let path = &args[1];
    let has_header = !args.iter().any(|a| a == "--no-header");

    match count_rows(path, has_header) {
        Ok(count) => println!("{}", count),
        Err(e) => {
            eprintln!("Error: {}", e);
            exit(1);
        }
    }
}

