    match count_rows(file, has_header) {
        Ok((total, data_rows)) => {
            if has_header {
                println!("Total rows: {}", total);
                println!("Data rows (excluding header): {}", data_rows);
            } else {
                println!("Total rows: {}", total);
            }
        }
        Err(e) => {
            eprintln!("Error reading '{}': {}", file_path, e);
