fn count_rows(file: File, has_header: bool) -> io::Result<(u64, u64)> {
    let reader = BufReader::new(file);
    let mut rdr = csv::ReaderBuilder::new()
        .has_headers(false)
        .flexible(true)
        .from_reader(reader);

    let mut total: u64 = 0;
    for result in rdr.records() {
        let _record = result.map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;
        total += 1;
    }

    let data_rows = if has_header && total > 0 { total - 1 } else { total };
    Ok((total, data_rows))
}

